21	void ContextUpdater::Store(Deserializer::KeyType const& k,
22	                           std::wstring const& value) {
23	  if (!m_pTarget->p_context || k.size() < 2)
24	    return;
25	
26	  if (k[1] == L"preedit") {
27	    _StoreText(m_pTarget->p_context->preedit, k, value);
28	    return;
29	  }
30	
31	  if (k[1] == L"aux") {
32	    _StoreText(m_pTarget->p_context->aux, k, value);
33	    return;
34	  }
35	
36	  if (k[1] == L"cand") {
37	    _StoreCand(k, value);
38	    return;
39	  }
40	}
41	
42	void ContextUpdater::_StoreText(Text& target,
43	                                Deserializer::KeyType k,
44	                                std::wstring const& value) {
45	  if (k.size() == 2) {
46	    target.clear();
47	    target.str = unescape_string(value);
48	    return;
49	  }
50	  if (k.size() == 3) {
51	    // ctx.preedit.cursor
52	    if (k[2] == L"cursor") {
53	      std::vector<std::wstring> vec;
54	      split(vec, value, L",");
55	      if (vec.size() < 2)
56	        return;
57	
58	      weasel::TextAttribute attr;
59	      attr.type = HIGHLIGHTED;
60	      attr.range.start = _wtoi(vec[0].c_str());
61	      attr.range.end = _wtoi(vec[1].c_str());
62	      attr.range.cursor = _wtoi(vec[2].c_str());
63	
64	      target.attributes.push_back(attr);
65	      return;
66	    }
67	  }
68	}
