70	void ContextUpdater::_StoreCand(Deserializer::KeyType k,
71	                                std::wstring const& value) {
72	  CandidateInfo& cinfo = m_pTarget->p_context->cinfo;
73	  std::wstringstream ss(value);
74	  boost::archive::text_wiarchive ia(ss);
75	
76	  TryDeserialize(ia, cinfo);
77	
78	  for (auto& cand : cinfo.candies)
79	    cand.str = unescape_string(cand.str);
80	  for (auto& lalel : cinfo.labels)
81	    lalel.str = unescape_string(lalel.str);
82	  for (auto& comment : cinfo.comments)
83	    comment.str = unescape_string(comment.str);
84	}
